var oauth2 = {
    clientId: 'YOUR-CLIENT-ID',
    authorizationEndpoint: 'https://accounts.google.com/o/oauth2/v2/auth',
    redirectUri: window.location.origin + '/redirect.html',
    scope: 'openid profile email',
    accessTokenKeyName: 'access_token'
};

function getAuthUrl(clientId, redirectUri, scope) {
  return (oauth2.authorizationEndpoint + 
          '?response_type=token' +  
          '&client_id='     + encodeURIComponent(clientId) + 
          '&redirect_uri='  + encodeURIComponent(redirectUri) + 
          '&scope='          + encodeURIComponent(scope));
}

function handleResponse(accessToken, accessTokenKeyName){ 
    sessionStorage.setItem(accessTokenKeyName, accessToken);  
    window.location = "/"; // Redirect back to the main page after token is stored in session storage.
}

window.addEventListener('load', function(){
    var authUrl = getAuthUrl(oauth2.clientId, oauth2.redirectUri, oauth2.scope);
    window.location = authUrl; // Redirect to the OAuth 2.0 provider.
});

window.addEventListener('hashchange', function(){
   if (/access_token=([^&]*)/.test(document.location.hash)) {
      var matches = /access_token=([^&]*)/.exec(document.location.hash); 
      handleResponse(matches[1], oauth2.accessTokenKeyName);  
    } else if (/error=(.+)$/.test(document.location.hash)) {
        alert("Error: " + /error=(.+)$/.exec(document.location.hash)[1]); 
    }
});